#!/usr/bin/env python3 """Create Discord webhooks for GitHubCitadel relay (fallback when native OAuth unavailable).""" from __future__ import annotations import json import os import urllib.request from pathlib import Path ENV_FILE = Path(r"D:\HermesData\.env") MAP_FILE = Path(r"D:\PhronesisVault\Discord\citadel-channel-map.json") OUT_FILE = Path(r"D:\HermesData\secrets\github-discord-webhooks.json") API = "https://discord.com/api/v10" TARGETS = { "deliverables": "GitHub Deliverables", "stack-health": "GitHub Stack Health", } def token() -> str: if os.getenv("DISCORD_BOT_TOKEN"): return os.getenv("DISCORD_BOT_TOKEN", "").strip() for line in ENV_FILE.read_text(encoding="utf-8").splitlines(): if line.startswith("DISCORD_BOT_TOKEN="): return line.split("=", 1)[1].strip().strip('"') raise SystemExit("DISCORD_BOT_TOKEN not found") def channel_ids() -> dict[str, str]: data = json.loads(MAP_FILE.read_text(encoding="utf-8")) channels = data.get("channels", {}) out: dict[str, str] = {} for name in TARGETS: if name in channels: out[name] = str(channels[name]["id"]) return out def api(method: str, path: str, body: dict | None = None) -> dict: headers = { "Authorization": f"Bot {token()}", "Content-Type": "application/json", "User-Agent": "PhronesisGitHubDiscordSetup/1.0", } data = json.dumps(body).encode("utf-8") if body is not None else None req = urllib.request.Request(f"{API}{path}", data=data, method=method, headers=headers) with urllib.request.urlopen(req, timeout=20) as resp: return json.loads(resp.read().decode("utf-8")) def list_webhooks(channel_id: str) -> list[dict]: return api("GET", f"/channels/{channel_id}/webhooks") def create_webhook(channel_id: str, name: str) -> dict: return api("POST", f"/channels/{channel_id}/webhooks", {"name": name}) def main() -> None: ids = channel_ids() missing = [k for k in TARGETS if k not in ids] if missing: raise SystemExit(f"channels not in map: {missing}") results: dict[str, dict] = {} for slug, label in TARGETS.items(): cid = ids[slug] existing = [w for w in list_webhooks(cid) if w.get("name") == label] hook = existing[0] if existing else create_webhook(cid, label) results[slug] = { "channel_id": cid, "webhook_id": hook.get("id"), "name": hook.get("name"), "url": hook.get("url", ""), } OUT_FILE.parent.mkdir(parents=True, exist_ok=True) OUT_FILE.write_text(json.dumps(results, indent=2), encoding="utf-8") print(json.dumps({"ok": True, "written": str(OUT_FILE), "channels": list(results)})) if __name__ == "__main__": main()